import React from 'react';
import { NavLink } from 'react-router-dom';

const navigation = () => {
    return (
        <div className="navigation nav-section sticky-top p-3 w-100">
            <ul className="m-0 p-0 nav justify-content-center w-100">
                <NavLink exact = "true" to="/" className={({isActive}) => isActive ? "nav-active" : ""} className="nav-item bg-img-custom me-auto" >
                    
                </NavLink>
                <NavLink exact = "true" to="/" className={({isActive}) => isActive ? "nav-active" : ""} className="nav-item bg-img-custom me-auto" >
                    
                </NavLink>
                <li className="nav-item bg-img-custom my-auto me-auto nav-btn" >                   
                </li>
            </ul>
        </div>
    );
    const main = document.querySelector('main');
const navBtn = document.querySelector('.nav-btn');
const navDisplay = document.querySelector('.nav-display');

navBtn.addEventListener('click', () => {
    navDisplay.classList.toggle('nav-display-move');
    main.classList.toggle('blur-effect');
})
};

export default navigation;
